class Solution:
    def maxProductDifference(self, nums):
        s = sorted(nums)
        return s[-1] * s[-2] - s[0] * s[1]

solutions.javascript:
var maxProductDifference = function(nums) {
    const s = nums.slice().sort((a, b) => a - b);
    const n = s.length;
    return s[n - 1] * s[n - 2] - s[0] * s[1];
};
